import React from 'react';
import { MenuIcon, BellIcon } from './Icons';

interface TopNavProps {
  title: string;
  hasNotification?: boolean;
  onBellClick?: () => void;
}

const TopNav: React.FC<TopNavProps> = ({ title, hasNotification, onBellClick }) => {
  return (
    <header className="sticky top-0 z-40 w-full px-5 py-6 flex items-center justify-between bg-transparent backdrop-blur-sm">
      <button className="p-1 text-gray-400 hover:text-white transition-colors">
        <MenuIcon className="w-7 h-7" />
      </button>

      <div className="flex flex-col items-center">
        <h1 className="text-2xl font-bold tracking-tight text-white flex items-center gap-1">
          {title} <span className="text-yellow-400 text-3xl leading-none">.</span>
        </h1>
      </div>

      <button 
        onClick={onBellClick}
        className="relative p-1 text-gray-400 hover:text-white transition-colors"
      >
        <BellIcon className="w-7 h-7" />
        {hasNotification && (
          <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-[#0c1021]"></span>
        )}
      </button>
    </header>
  );
};

export default TopNav;

import React, { useState, useEffect, useCallback } from 'react';
import BottomNav from './components/BottomNav';
import TopNav from './components/TopNav';
import DailyDua from './components/DailyDua';
import ZikrCounter from './components/ZikrCounter';
import DuaJournal from './components/DuaJournal';
import AmeenWall from './components/AmeenWall';
import DuaCategories from './components/DuaCategories';
import SleepMode from './components/SleepMode';
import { AppView, ZikrReminder } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>(AppView.Home);
  const [isSleepMode, setIsSleepMode] = useState(false);
  const [hasNotification, setHasNotification] = useState(false);
  const [reminder, setReminder] = useState('');

  const handleSetView = useCallback((view: AppView) => {
    setActiveView(view);
  }, []);

  const handleEnterSleepMode = useCallback(() => {
    setIsSleepMode(true);
  }, []);

  const handleExitSleepMode = useCallback(() => {
    setIsSleepMode(false);
  }, []);

  useEffect(() => {
    const now = new Date();
    const hour = now.getHours();
    let currentReminder = '';

    if (hour >= 4 && hour < 12) {
      currentReminder = "🌅 Morning Reminder: Start with 'Alhamdulillah' today.";
    } else if (hour >= 12 && hour < 17) {
      currentReminder = "☀️ Afternoon Reminder: Take a moment for a short Dua.";
    } else if (hour >= 17 && hour < 21) {
        currentReminder = "🌙 Evening Reminder: Reflect on your day and say 'Astaghfirullah'.";
    } else {
        currentReminder = "🌌 Night Reminder: Recite Ayatul Kursi before sleeping.";
    }

    setReminder(currentReminder);
    setHasNotification(true);
  }, []);

  // Check for Custom Zikr Reminder
  useEffect(() => {
    const checkZikrReminder = () => {
      try {
        const saved = localStorage.getItem('zikrReminder');
        if (saved) {
          const settings: ZikrReminder = JSON.parse(saved);
          if (settings.enabled && settings.time) {
            const now = new Date();
            const currentTime = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
            const today = now.toDateString();

            if (settings.time === currentTime && settings.lastTriggered !== today) {
              setReminder(`🔔 It's time for your ${settings.zikrType} Zikr`);
              setHasNotification(true);

              const newSettings = { ...settings, lastTriggered: today };
              localStorage.setItem('zikrReminder', JSON.stringify(newSettings));
            }
          }
        }
      } catch (e) {
        console.error("Error checking zikr reminder:", e);
      }
    };

    const interval = setInterval(checkZikrReminder, 1000);
    return () => clearInterval(interval);
  }, []);

  if (isSleepMode) {
    return <SleepMode onExit={handleExitSleepMode} />;
  }

  const renderView = () => {
    switch (activeView) {
      case AppView.Home:
        return <DailyDua onEnterSleepMode={handleEnterSleepMode} />;
      case AppView.Zikr:
        return <ZikrCounter />;
      case AppView.Journal:
        return <DuaJournal />;
      case AppView.Ameen:
        return <AmeenWall />;
      case AppView.Categories:
        return <DuaCategories />;
      default:
        return <DailyDua onEnterSleepMode={handleEnterSleepMode} />;
    }
  };

  const clearNotification = () => {
    if (hasNotification && reminder) {
      alert(reminder);
      setHasNotification(false);
    }
  };

  return (
    <div className="min-h-screen w-full flex flex-col antialiased bg-[#0c1021]">
      <TopNav 
        title="Noor" 
        hasNotification={hasNotification} 
        onBellClick={clearNotification}
      />

      <main className="flex-grow w-full max-w-lg mx-auto px-5 pb-28">
        {renderView()}
      </main>

      <BottomNav activeView={activeView} setActiveView={handleSetView} />
      <audio id="global-audio-player" className="hidden"></audio>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Dua } from '../types';
import DuaCard from './DuaCard';
import { MoonIcon, SearchIcon } from './Icons';

interface DailyDuaProps {
  onEnterSleepMode: () => void;
}

const DailyDua: React.FC<DailyDuaProps> = ({ onEnterSleepMode }) => {
  const [dailyDua, setDailyDua] = useState<Dua | null>(null);
  const [allDuas, setAllDuas] = useState<Dua[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    fetch('/data/duas.json')
      .then(res => res.json())
      .then(data => {
        const loadedDuas = data.categories.flatMap((category: any) => category.duas);
        setAllDuas(loadedDuas);
      })
      .catch(err => console.error("Failed to load duas:", err));
  }, []);

  useEffect(() => {
    if (allDuas.length === 0) return;

    const today = new Date().toDateString();
    const lastVisitDate = localStorage.getItem('lastVisitDate');
    const storedDuaId = localStorage.getItem('dailyDuaId');

    let duaToSet: Dua | null = null;

    if (lastVisitDate === today && storedDuaId) {
      duaToSet = allDuas.find(d => d.id === parseInt(storedDuaId)) || null;
    } 

    if (!duaToSet) {
      const randomIndex = Math.floor(Math.random() * allDuas.length);
      duaToSet = allDuas[randomIndex];
      localStorage.setItem('dailyDuaId', String(duaToSet.id));
      localStorage.setItem('lastVisitDate', today);
    }

    setDailyDua(duaToSet);
  }, [allDuas]);

  const filteredDuas = allDuas.filter(dua => {
      const query = searchQuery.toLowerCase();
      return (
          dua.translation_en.toLowerCase().includes(query) ||
          dua.transliteration.toLowerCase().includes(query) ||
          dua.arabic.includes(query) ||
          dua.translation_ur.includes(query)
      );
  });

  return (
    <div className="space-y-6">
        {/* Intro Message */}
        <div className="py-2">
            <h2 className="text-3xl font-bold text-white leading-tight">
                Let's find your perfect <br /> 
                <span className="text-yellow-400">Dua for you!</span>
            </h2>
        </div>

        {/* Search Bar - DubiCars Style */}
        <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <SearchIcon className="h-5 w-5 text-gray-500" aria-hidden="true" />
            </div>
            <input
                type="text"
                className="block w-full pl-12 pr-12 py-4 border-0 rounded-2xl bg-[#1b1b2f] text-gray-100 placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-yellow-400/30 transition-all duration-300 shadow-lg"
                placeholder="Search for Dua, category or keyword"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
            />
            <div className="absolute inset-y-0 right-0 pr-4 flex items-center cursor-pointer">
                <div className="p-1 border border-gray-700 rounded-md">
                   <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="text-gray-400">
                      <path d="M3 6H21M6 12H18M10 18H14" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                   </svg>
                </div>
            </div>
        </div>

      {searchQuery ? (
          <div className="space-y-4 animate-fade-in">
             <p className="text-sm text-gray-400 ml-1 font-medium">Found {filteredDuas.length} results</p>
             {filteredDuas.map(dua => (
                 <DuaCard key={dua.id} dua={dua} />
             ))}
             {filteredDuas.length === 0 && (
                 <div className="text-center text-gray-500 py-20 flex flex-col items-center">
                     <SearchIcon className="w-12 h-12 mb-4 opacity-20" />
                     <p>No Duas found matching "{searchQuery}"</p>
                 </div>
             )}
          </div>
      ) : (
          <>
            {/* Recent Searches simulation */}
            <div className="space-y-3">
                <div className="flex items-center gap-2 text-gray-400 text-sm">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    <span>Your recent searches</span>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
