            const Icon = getCategoryIcon(category.name);
            const cleanName = category.name.replace(/^[^\w]+/, '').trim();
            return (
                <button
                  key={category.name}
                  onClick={() => setSelectedCategory(category)}
                  className="relative group p-6 rounded-[2rem] bg-[#1b1b2f] border border-white/5 hover:border-yellow-400/30 transition-all duration-300 text-left flex flex-col items-center text-center overflow-hidden"
