      {/* Full Dua Modal */}
      {isDuaModalOpen && dailyDua && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-fade-in" onClick={() => setIsDuaModalOpen(false)}>
