                    <span>Quick filters</span>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                    {['Morning', 'Protection', 'Anxiety', 'Gratitude', 'Rizq', 'Travel'].map(tag => (
                        <button 
