import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Dua } from '../types';
import { XMarkIcon } from './Icons';
import duaData from '../data/duas.json';

interface SleepModeProps {
  onExit: () => void;
}

const SleepMode: React.FC<SleepModeProps> = ({ onExit }) => {
  const [playlist, setPlaylist] = useState<Dua[]>([]);
  const [currentDua, setCurrentDua] = useState<Dua | null>(null);
  const [audioAvailable, setAudioAvailable] = useState(true);
  const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
  const currentTrackIndexRef = useRef(0);

  useEffect(() => {
    // Bundled data sleep fix
    const sleepCategory = duaData.categories.find((c: any) => c.name.toLowerCase().includes('sleep'));
    const sleepDuas = sleepCategory?.duas.filter((d: any) => d.audio) || [];

    // If no specific audio, we show text recitations for visual peace
    const allSleepDuas = sleepCategory?.duas || [];

    if (allSleepDuas.length > 0) {
      setPlaylist(allSleepDuas);
      if (sleepDuas.length === 0) {
        setAudioAvailable(false);
      }
    } else {
      setAudioAvailable(false);
    }
  }, []);

  const playNextTrack = useCallback(() => {
    if (playlist.length === 0) return;

    if (currentTrackIndexRef.current >= playlist.length) {
      currentTrackIndexRef.current = 0;
    }

    const track = playlist[currentTrackIndexRef.current];
    setCurrentDua(track);

    const audioPlayer = audioPlayerRef.current;
    if (audioPlayer && track.audio) {
        audioPlayer.src = track.audio;
        const playPromise = audioPlayer.play();
        if(playPromise !== undefined) {
            playPromise.catch(e => {
                console.error("Audio play failed:", e);
                currentTrackIndexRef.current++;
                playNextTrack();
            });
        }
        currentTrackIndexRef.current++;
    } else {
      // If no audio, rotate text every 15 seconds
      const timer = setTimeout(() => {
        currentTrackIndexRef.current++;
        playNextTrack();
      }, 15000);
      return () => clearTimeout(timer);
    }
  }, [playlist]);

  useEffect(() => {
    if (playlist.length === 0) return;

    if (!audioPlayerRef.current) {
        audioPlayerRef.current = document.getElementById('global-audio-player') as HTMLAudioElement;
    }

    const audioPlayer = audioPlayerRef.current;
    if(audioPlayer) {
        audioPlayer.pause();
        audioPlayer.currentTime = 0;
        audioPlayer.onended = playNextTrack;
        playNextTrack();
    }

    return () => {
        if(audioPlayer) {
            audioPlayer.pause();
            audioPlayer.onended = null;
        }
    }
  }, [playNextTrack, playlist]);

  return (
    <div className="fixed inset-0 bg-gradient-to-br from-[#0c1021] to-[#1b1b2f] flex flex-col items-center justify-center p-8 z-50 animate-fade-in overflow-hidden">
        {/* Ambient background glows */}
        <div className="absolute top-1/4 -left-20 w-80 h-80 bg-indigo-500/5 blur-[120px] rounded-full"></div>
        <div className="absolute bottom-1/4 -right-20 w-80 h-80 bg-blue-500/5 blur-[120px] rounded-full"></div>

        <button onClick={onExit} className="absolute top-6 right-6 text-gray-500 hover:text-white p-3 bg-white/5 rounded-full transition-colors z-20">
            <XMarkIcon className="w-6 h-6"/>
        </button>

        <div className="text-center max-w-lg z-10">
            {currentDua ? (
                <div key={currentDua.id} className="animate-fade-in-out space-y-12">
                    <p className="font-arabic text-5xl md:text-7xl text-white leading-[1.8] drop-shadow-2xl">
                        {currentDua.arabic}
                    </p>
                    <div className="space-y-4">
                        <p className="text-xl md:text-2xl text-gray-300 font-medium px-4 leading-relaxed italic">"{currentDua.translation_en}"</p>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.5em] font-black">Rest with Remembrance</p>
                    </div>
                </div>
            ) : (
                <div className="flex flex-col items-center space-y-4">
                  <div className="w-12 h-12 border-2 border-white/5 border-t-white/40 rounded-full animate-spin"></div>
                  <p className="text-xs text-gray-500 uppercase tracking-widest font-black">Creating Silence...</p>
                </div>
            )}
        </div>

        <style>{`
            @keyframes fade-in-out {
                0%, 100% { opacity: 0; transform: translateY(10px); }
                10%, 90% { opacity: 1; transform: translateY(0); }
            }
            .animate-fade-in-out {
                animation: fade-in-out 15s ease-in-out infinite;
            }
            @keyframes fade-in {
                from { opacity: 0; }
                to { opacity: 1; }
            }
            .animate-fade-in {
                animation: fade-in 1s ease-in-out;
            }
        `}</style>
    </div>
  );
};

export default SleepMode;

