  const [aiRecommendation, setAiRecommendation] = useState<{reflection: string, suggestedDuaId: number} | null>(null);
  const [showCompassModal, setShowCompassModal] = useState(false);

  useEffect(() => {
    // Correctly loading from the bundled TS data to avoid resolution errors on Vercel
    const loadedDuas = duaData.categories.flatMap((category: any) => category.duas);
    setAllDuas(loadedDuas);
  }, []);

  useEffect(() => {
    if (allDuas.length === 0) return;

    const today = new Date().toDateString();
    const lastVisitDate = localStorage.getItem('lastVisitDate');
    const storedDuaId = localStorage.getItem('dailyDuaId');

    let duaToSet: Dua | null = null;

    if (lastVisitDate === today && storedDuaId) {
      duaToSet = allDuas.find(d => d.id === parseInt(storedDuaId)) || null;
    } 

    if (!duaToSet) {
      const randomIndex = Math.floor(Math.random() * allDuas.length);
      duaToSet = allDuas[randomIndex];
      localStorage.setItem('dailyDuaId', String(duaToSet.id));
      localStorage.setItem('lastVisitDate', today);
    }

    setDailyDua(duaToSet);
  }, [allDuas]);

  const handleCompassSearch = async () => {
    if (!moodInput.trim()) return;
    setIsCompassLoading(true);
    setAiRecommendation(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const duaContext = allDuas.map(d => ({id: d.id, title: d.translation_en})).slice(0, 50);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `The user says: "${moodInput}". Based on the following list of Islamic Duas, pick the best one by ID and provide a short, 2-sentence spiritual reflection.
        Library: ${JSON.stringify(duaContext)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              reflection: { type: Type.STRING },
              suggestedDuaId: { type: Type.NUMBER }
            },
            required: ["reflection", "suggestedDuaId"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setAiRecommendation(result);
      setShowCompassModal(true);
    } catch (error) {
      console.error("AI Compass failed:", error);
      alert("The spiritual compass is recalibrating. Please try again in a moment.");
    } finally {
      setIsCompassLoading(false);
    }
  };

  const filteredDuas = allDuas.filter(dua => {
      const query = searchQuery.toLowerCase();
      return (
          dua.translation_en.toLowerCase().includes(query) ||
          dua.transliteration.toLowerCase().includes(query) ||
          dua.arabic.includes(query) ||
          dua.translation_ur.includes(query)
      );
  });

  const recommendedDua = aiRecommendation ? allDuas.find(d => d.id === aiRecommendation.suggestedDuaId) : null;

  return (
    <div className="space-y-6">
        <div className="py-2">
            <h2 className="text-3xl font-bold text-white leading-tight">
                Welcome to <br /> 
                <span className="text-yellow-400">Your Sanctuary</span>
            </h2>
        </div>

        {/* Spiritual Compass UI */}
        <div className="bg-gradient-to-br from-indigo-900/40 to-indigo-900/10 border border-white/5 rounded-[2rem] p-6 shadow-xl">
            <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-yellow-400/10 rounded-xl text-yellow-400">
                    <CompassIcon className="w-5 h-5"/>
                </div>
                <div>
                  <h3 className="text-sm font-bold text-white">Spiritual Compass</h3>
                  <p className="text-[10px] text-gray-500 uppercase tracking-widest">How is your heart today?</p>
                </div>
            </div>
            <div className="relative">
                <input 
                  type="text" 
                  value={moodInput}
                  onChange={(e) => setMoodInput(e.target.value)}
                  placeholder="e.g. I am feeling very overwhelmed"
                  className="w-full bg-[#0c1021]/60 border border-white/10 rounded-2xl py-3 pl-4 pr-12 text-sm text-gray-100 placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-yellow-400/30"
                />
                <button 
                  onClick={handleCompassSearch}
                  disabled={isCompassLoading}
                  className="absolute right-2 top-2 p-1.5 bg-yellow-400 text-gray-900 rounded-xl hover:bg-yellow-300 transition-colors disabled:opacity-50"
                >
                  {isCompassLoading ? (
                    <div className="w-5 h-5 border-2 border-gray-900/20 border-t-gray-900 rounded-full animate-spin"></div>
                  ) : (
                    <SparklesIcon className="w-5 h-5"/>
                  )}
                </button>
            </div>
        </div>

        {/* Refined Search Bar */}
        <div className="relative">
            <input
                type="text"
                className="block w-full pl-6 pr-12 py-4 border-0 rounded-2xl bg-[#1b1b2f] text-gray-100 placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-yellow-400/30 transition-all duration-300 shadow-lg"
                placeholder="Search Duas..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
            />
            <div className="absolute inset-y-0 right-0 pr-4 flex items-center">
                {searchQuery ? (
                  <button onClick={() => setSearchQuery('')} className="text-gray-500 hover:text-white">
                    <XMarkIcon className="w-5 h-5" />
                  </button>
                ) : (
                  <SearchIcon className="w-5 h-5 text-gray-500" />
                )}
            </div>
        </div>

      {searchQuery ? (
          <div className="space-y-4 animate-fade-in">
             {filteredDuas.map(dua => (
                 <DuaCard key={dua.id} dua={dua} />
             ))}
             {filteredDuas.length === 0 && (
                 <div className="text-center text-gray-500 py-10">No results found</div>
             )}
          </div>
      ) : (
          <>
            {/* Daily Feature Card */}
            <div 
              onClick={() => setIsDuaModalOpen(true)}
              className="relative rounded-[2.5rem] overflow-hidden shadow-2xl h-64 w-full flex items-end group cursor-pointer"
            >
                <div className="absolute inset-0 bg-gradient-to-br from-[#1b1b2f] to-[#0c1021] z-0"></div>

                <div className="relative z-10 p-8 w-full flex flex-col justify-end">
                   <h3 className="text-2xl font-bold text-white mb-3">Dua of the Day</h3>

                   {dailyDua && (
                       <div className="bg-[#0c1021]/80 backdrop-blur-xl rounded-2xl p-4 border border-white/10">
                           <p className="text-gray-300 text-sm line-clamp-2 italic">"{dailyDua.translation_en}"</p>
                       </div>
                   )}
                </div>
            </div>

            <button
                onClick={onEnterSleepMode}
                className="w-full flex items-center justify-between bg-white/5 backdrop-blur-sm text-gray-100 px-6 py-6 rounded-[2rem] border border-white/5 group hover:bg-white/10 transition-all"
            >
                <div className="flex items-center gap-4">
                    <div className="p-3 bg-indigo-500/10 rounded-2xl text-indigo-400">
                        <MoonIcon className="w-6 h-6"/>
                    </div>
                    <span className="text-lg font-bold">Sleep Mode</span>
                </div>
                <div className="text-gray-500 group-hover:text-white">→</div>
            </button>
          </>
      )}

      {/* AI Result Modal */}
      {showCompassModal && recommendedDua && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/95 backdrop-blur-3xl animate-fade-in" onClick={() => setShowCompassModal(false)}>
           <div className="relative w-full max-w-md bg-[#0c1021] border border-white/10 rounded-[3rem] p-10 shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
              <h2 className="text-xl font-bold text-yellow-400">A Reflection for You</h2>
              <p className="text-gray-200 italic">"{aiRecommendation?.reflection}"</p>
              <div className="border-t border-white/10 pt-6">
                <DuaCard dua={recommendedDua} />
              </div>
              <button onClick={() => setShowCompassModal(false)} className="w-full bg-yellow-400 text-gray-900 py-3 rounded-2xl font-bold">Close</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default DailyDua;

import React, { useState, useEffect } from 'react';
import { Dua } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';
import { HeartIcon, PlayIcon, ShareIcon } from './Icons';

interface DuaCardProps {
  dua: Dua;
}

const DuaCard: React.FC<DuaCardProps> = ({ dua }) => {
  const [favorites, setFavorites] = useLocalStorage<number[]>('favoriteDuas', []);
  const [isFavorite, setIsFavorite] = useState(false);
  const [showCopyFeedback, setShowCopyFeedback] = useState(false);

  useEffect(() => {
    setIsFavorite(favorites.includes(dua.id));
  }, [favorites, dua.id]);

  const toggleFavorite = () => {
    setFavorites(prev => 
      isFavorite ? prev.filter(id => id !== dua.id) : [...prev, dua.id]
    );
  };

  const shareDua = async () => {
    const shareText = `Dua: ${dua.arabic}\n\nTranslation: ${dua.translation_en}\n\nShared from Noor App.`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Islamic Dua',
          text: shareText,
          url: window.location.href,
        });
      } catch (error) {
        console.error("Error sharing:", error);
      }
    } else {
      try {
        await navigator.clipboard.writeText(shareText);
        setShowCopyFeedback(true);
        setTimeout(() => setShowCopyFeedback(false), 2000);
      } catch (err) {
        console.error("Failed to copy:", err);
      }
    }
  };

  const playAudio = () => {
    const audioPlayer = document.getElementById('global-audio-player') as HTMLAudioElement;
    if (audioPlayer && dua.audio) {
      audioPlayer.pause();
      audioPlayer.currentTime = 0;
      audioPlayer.src = dua.audio;
      audioPlayer.play().catch(console.error);
    }
  };

  return (
    <div className="bg-gray-800/50 backdrop-blur-sm border border-gray-700/50 rounded-2xl p-6 shadow-lg space-y-4 animate-fade-in relative">
      {showCopyFeedback && (
        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-yellow-400 text-gray-900 px-3 py-1 rounded-full text-[10px] font-bold z-20">
          Copied!
        </div>
      )}

      <p className="font-arabic text-3xl text-right leading-relaxed text-white">{dua.arabic}</p>

      <div className="pt-2 space-y-2">
        <p className="text-gray-400 italic text-sm">{dua.transliteration}</p>
        <p className="text-gray-200 text-sm">"{dua.translation_en}"</p>
      </div>

      <div className="flex justify-center space-x-3 pt-4 border-t border-gray-700/50">
        {dua.audio && (
          <button onClick={playAudio} className="p-3 bg-yellow-400/10 text-yellow-400 rounded-full hover:bg-yellow-400/20">
            <PlayIcon className="w-5 h-5"/>
          </button>
        )}
        <button 
          onClick={toggleFavorite}
          className={`flex items-center gap-2 px-6 py-2 rounded-full transition-all ${isFavorite ? 'bg-pink-500/20 text-pink-400' : 'bg-gray-700/50 text-gray-300'}`}
        >
          <HeartIcon className={`w-5 h-5 ${isFavorite ? 'fill-current' : ''}`}/>
          <span className="text-xs font-bold">{isFavorite ? 'Saved' : 'Save'}</span>
        </button>
        <button onClick={shareDua} className="p-3 bg-indigo-500/10 text-indigo-400 rounded-full hover:bg-indigo-500/20">
          <ShareIcon className="w-5 h-5"/>
        </button>
      </div>
    </div>
  );
};

export default DuaCard;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { DuaCategory, Dua } from '../types';
import DuaCard from './DuaCard';
import { 
    PlayIcon, 
    SunIcon, 
    CloudIcon, 
    ShieldCheckIcon, 
    SparklesIcon, 
    BriefcaseIcon, 
    GlobeAltIcon, 
    LeafIcon, 
    GiftIcon, 
    HeartIcon, 
    MoonIcon, 
    CategoryIcon 
} from './Icons';
import { duaData } from '../data/duas';

const DuaCategories: React.FC = () => {
  const [categories, setCategories] = useState<DuaCategory[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState<DuaCategory | null>(null);

  useEffect(() => {
    setCategories(duaData.categories);
    setIsLoading(false);
  }, []);

  const getCategoryIcon = (name: string) => {
      const lowerName = name.toLowerCase();
      if (lowerName.includes("morning")) return SunIcon;
      if (lowerName.includes("forgiveness")) return CloudIcon;
      if (lowerName.includes("protection")) return ShieldCheckIcon;
      if (lowerName.includes("gratitude")) return GiftIcon;
      if (lowerName.includes("zikr")) return SparklesIcon;
      if (lowerName.includes("stress")) return HeartIcon;
      if (lowerName.includes("health")) return LeafIcon;
      if (lowerName.includes("rizq")) return BriefcaseIcon;
      if (lowerName.includes("travel")) return GlobeAltIcon;
      return CategoryIcon;
  };

  if (selectedCategory) {
    return (
      <div className="space-y-6 animate-fade-in">
        <button onClick={() => setSelectedCategory(null)} className="text-gray-500 hover:text-white flex items-center gap-2 mb-4">
          ← Back
        </button>
        <h1 className="text-2xl font-bold text-white mb-6">{selectedCategory.name}</h1>
        <div className="space-y-6">
          {selectedCategory.duas.map(dua => (
            <DuaCard key={dua.id} dua={dua} />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <h1 className="text-3xl font-bold text-white mb-8">Categories</h1>
      <div className="grid grid-cols-2 gap-4">
        {categories.map((category) => {
          const Icon = getCategoryIcon(category.name);
          return (
              <button
                key={category.name}
                onClick={() => setSelectedCategory(category)}
                className="p-6 rounded-3xl bg-white/5 border border-white/5 hover:border-yellow-400/30 transition-all text-center flex flex-col items-center gap-4"
              >
                <div className="p-4 bg-yellow-400/10 rounded-2xl text-yellow-400">
                  <Icon className="w-8 h-8" />
                </div>
                <h2 className="text-sm font-bold text-white">{category.name.replace(/^[^\w\s]+/, '').trim()}</h2>
              </button>
          );
        })}
      </div>
    </div>
  );
};

export default DuaCategories;

import React, { useState, useEffect } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import { JournalEntry } from '../types';
import { CheckCircleIcon, PlusCircleIcon, XMarkIcon, JournalIcon } from './Icons';
import { quotesData } from '../data/quotes';

const DuaJournal: React.FC = () => {
  const [journal, setJournal] = useLocalStorage<JournalEntry[]>('duaJournal', []);
  const [activeTab, setActiveTab] = useState<'pending' | 'answered'>('pending');
  const [showForm, setShowForm] = useState(false);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [reflection, setReflection] = useState<string | null>(null);

  const addEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !content) return;
    const newEntry: JournalEntry = {
      id: new Date().toISOString(),
      title,
      content,
      createdAt: new Date().toISOString(),
      status: 'pending',
    };
    setJournal(prev => [newEntry, ...prev]);
    setTitle('');
    setContent('');
    setShowForm(false);
  };

  const toggleStatus = (id: string) => {
    setJournal(prev =>
      prev.map(entry =>
        entry.id === id ? { ...entry, status: entry.status === 'pending' ? 'answered' : 'pending' } : entry
      )
    );
  };

  const showReflection = () => {
    const randomIndex = Math.floor(Math.random() * quotesData.quotes.length);
    setReflection(quotesData.quotes[randomIndex]);
  };

  const deleteEntry = (id: string) => {
    setJournal(prev => prev.filter(entry => entry.id !== id));
  };

  const filteredEntries = journal.filter(entry => entry.status === activeTab);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold text-white">Journal</h1>
        <button onClick={showReflection} className="text-xs text-yellow-400 font-bold uppercase tracking-widest">Reflect</button>
      </div>

      {reflection && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-6" onClick={() => setReflection(null)}>
          <div className="bg-gray-800 border border-yellow-400/50 rounded-2xl p-6 text-center max-w-sm">
            <p className="text-white">"{reflection}"</p>
          </div>
        </div>
      )}

      <div className="flex bg-gray-800/60 rounded-full p-1">
        <button onClick={() => setActiveTab('pending')} className={`flex-1 py-2 rounded-full text-xs font-bold transition-all ${activeTab === 'pending' ? 'bg-yellow-400 text-gray-900' : 'text-gray-500'}`}>My Duas</button>
        <button onClick={() => setActiveTab('answered')} className={`flex-1 py-2 rounded-full text-xs font-bold transition-all ${activeTab === 'answered' ? 'bg-yellow-400 text-gray-900' : 'text-gray-500'}`}>Blessings</button>
      </div>

      <div className="space-y-4">
        {filteredEntries.map(entry => (
          <div key={entry.id} className="bg-white/5 p-6 rounded-[2rem] border border-white/5 relative group">
            <h3 className="font-bold text-white">{entry.title}</h3>
            <p className="text-gray-400 text-sm mt-2">{entry.content}</p>
            <div className="absolute top-4 right-4 flex gap-2">
                <button onClick={() => toggleStatus(entry.id)} className="text-green-400"><CheckCircleIcon className="w-5 h-5"/></button>
                <button onClick={() => deleteEntry(entry.id)} className="text-red-400"><XMarkIcon className="w-5 h-5"/></button>
            </div>
          </div>
        ))}
      </div>

      <button onClick={() => setShowForm(true)} className="fixed bottom-28 right-6 bg-yellow-400 text-gray-900 w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-2xl z-40">
        <PlusCircleIcon className="w-8 h-8"/>
      </button>

      {showForm && (
        <div className="fixed inset-0 bg-black/90 z-50 flex items-center justify-center p-6" onClick={() => setShowForm(false)}>
            <form onSubmit={addEntry} className="bg-gray-900 p-8 rounded-[2rem] w-full max-w-md space-y-4" onClick={e => e.stopPropagation()}>
                <h2 className="text-xl font-bold text-white">New Entry</h2>
                <input type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="Title" className="w-full bg-gray-800 border-0 rounded-xl px-4 py-3 text-white" />
                <textarea value={content} onChange={e => setContent(e.target.value)} placeholder="Content" rows={4} className="w-full bg-gray-800 border-0 rounded-xl px-4 py-3 text-white"></textarea>
                <div className="flex gap-4">
                    <button type="button" onClick={() => setShowForm(false)} className="flex-1 py-3 text-gray-400">Cancel</button>
                    <button type="submit" className="flex-1 py-3 bg-yellow-400 text-gray-900 font-bold rounded-xl">Save</button>
                </div>
            </form>
        </div>
      )}
    </div>
  );
};

export default DuaJournal;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Dua } from '../types';
import { XMarkIcon } from './Icons';
import { duaData } from '../data/duas';

interface SleepModeProps {
  onExit: () => void;
}

const SleepMode: React.FC<SleepModeProps> = ({ onExit }) => {
  const [playlist, setPlaylist] = useState<Dua[]>([]);
  const [currentDua, setCurrentDua] = useState<Dua | null>(null);
  const currentTrackIndexRef = useRef(0);

  useEffect(() => {
    const sleepCategory = duaData.categories.find((c: any) => c.name.toLowerCase().includes('sleep'));
    const sleepDuas = sleepCategory?.duas || [];
    setPlaylist(sleepDuas);
  }, []);

  const playNextTrack = useCallback(() => {
    if (playlist.length === 0) return;
    if (currentTrackIndexRef.current >= playlist.length) {
      currentTrackIndexRef.current = 0;
    }
    setCurrentDua(playlist[currentTrackIndexRef.current]);
    currentTrackIndexRef.current++;
  }, [playlist]);

  useEffect(() => {
    if (playlist.length === 0) return;
    playNextTrack();
    const interval = setInterval(playNextTrack, 10000);
    return () => clearInterval(interval);
  }, [playNextTrack, playlist]);

  return (
    <div className="fixed inset-0 bg-[#0c1021] flex flex-col items-center justify-center p-8 z-50">
        <button onClick={onExit} className="absolute top-6 right-6 text-gray-500 hover:text-white p-3 bg-white/5 rounded-full transition-colors">
            <XMarkIcon className="w-6 h-6"/>
        </button>
        <div className="text-center max-w-lg space-y-12 animate-fade-in">
            {currentDua && (
                <>
                    <p className="font-arabic text-5xl md:text-7xl text-white leading-relaxed">{currentDua.arabic}</p>
                    <p className="text-xl md:text-2xl text-gray-400 italic">"{currentDua.translation_en}"</p>
                </>
            )}
        </div>
    </div>
  );
};

export default SleepMode;

import React, { useState, useEffect } from 'react';
import { Dua } from '../types';
import DuaCard from './DuaCard';
import { MoonIcon, SearchIcon, XMarkIcon, SparklesIcon, CompassIcon } from './Icons';
import { GoogleGenAI, Type } from "@google/genai";
import { duaData } from '../data/duas';

interface DailyDuaProps {
  onEnterSleepMode: () => void;
}

const DailyDua: React.FC<DailyDuaProps> = ({ onEnterSleepMode }) => {
  const [dailyDua, setDailyDua] = useState<Dua | null>(null);
  const [allDuas, setAllDuas] = useState<Dua[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isDuaModalOpen, setIsDuaModalOpen] = useState(false);

  // AI Compass State
  const [moodInput, setMoodInput] = useState('');
  const [isCompassLoading, setIsCompassLoading] = useState(false);
  const [aiRecommendation, setAiRecommendation] = useState<{reflection: string, suggestedDuaId: number} | null>(null);
  const [showCompassModal, setShowCompassModal] = useState(false);

  useEffect(() => {
    // Correctly loading from the bundled TS data to avoid resolution errors on Vercel
    const loadedDuas = duaData.categories.flatMap((category) => category.duas);
    setAllDuas(loadedDuas);
  }, []);

  useEffect(() => {
    if (allDuas.length === 0) return;

    const today = new Date().toDateString();
    const lastVisitDate = localStorage.getItem('lastVisitDate');
    const storedDuaId = localStorage.getItem('dailyDuaId');

    let duaToSet: Dua | null = null;

    if (lastVisitDate === today && storedDuaId) {
      duaToSet = allDuas.find(d => d.id === parseInt(storedDuaId)) || null;
    } 

    if (!duaToSet) {
      const randomIndex = Math.floor(Math.random() * allDuas.length);
      duaToSet = allDuas[randomIndex];
      localStorage.setItem('dailyDuaId', String(duaToSet.id));
      localStorage.setItem('lastVisitDate', today);
    }

    setDailyDua(duaToSet);
  }, [allDuas]);

  const handleCompassSearch = async () => {
    if (!moodInput.trim()) return;
    setIsCompassLoading(true);
    setAiRecommendation(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const duaContext = allDuas.map(d => ({id: d.id, title: d.translation_en})).slice(0, 50);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `The user says: "${moodInput}". Based on the following list of Islamic Duas, pick the best one by ID and provide a short, 2-sentence spiritual reflection.
        Library: ${JSON.stringify(duaContext)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              reflection: { type: Type.STRING },
              suggestedDuaId: { type: Type.NUMBER }
            },
            required: ["reflection", "suggestedDuaId"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setAiRecommendation(result);
      setShowCompassModal(true);
    } catch (error) {
      console.error("AI Compass failed:", error);
      alert("The spiritual compass is recalibrating. Please try again in a moment.");
    } finally {
      setIsCompassLoading(false);
    }
  };

  const filteredDuas = allDuas.filter(dua => {
      const query = searchQuery.toLowerCase();
      return (
          dua.translation_en.toLowerCase().includes(query) ||
          dua.transliteration.toLowerCase().includes(query) ||
          dua.arabic.includes(query) ||
          dua.translation_ur.includes(query)
      );
  });

  const recommendedDua = aiRecommendation ? allDuas.find(d => d.id === aiRecommendation.suggestedDuaId) : null;

  return (
    <div className="space-y-6">
        <div className="py-2">
            <h2 className="text-3xl font-bold text-white leading-tight">
                Welcome to <br /> 
                <span className="text-yellow-400">Your Sanctuary</span>
            </h2>
        </div>

        {/* Spiritual Compass UI */}
        <div className="bg-gradient-to-br from-indigo-900/40 to-indigo-900/10 border border-white/5 rounded-[2rem] p-6 shadow-xl">
            <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-yellow-400/10 rounded-xl text-yellow-400">
                    <CompassIcon className="w-5 h-5"/>
                </div>
                <div>
                  <h3 className="text-sm font-bold text-white">Spiritual Compass</h3>
                  <p className="text-[10px] text-gray-500 uppercase tracking-widest">How is your heart today?</p>
                </div>
            </div>
            <div className="relative">
                <input 
                  type="text" 
                  value={moodInput}
                  onChange={(e) => setMoodInput(e.target.value)}
                  placeholder="e.g. I am feeling very overwhelmed"
                  className="w-full bg-[#0c1021]/60 border border-white/10 rounded-2xl py-3 pl-4 pr-12 text-sm text-gray-100 placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-yellow-400/30"
                />
                <button 
                  onClick={handleCompassSearch}
                  disabled={isCompassLoading}
                  className="absolute right-2 top-2 p-1.5 bg-yellow-400 text-gray-900 rounded-xl hover:bg-yellow-300 transition-colors disabled:opacity-50"
                >
                  {isCompassLoading ? (
                    <div className="w-5 h-5 border-2 border-gray-900/20 border-t-gray-900 rounded-full animate-spin"></div>
                  ) : (
                    <SparklesIcon className="w-5 h-5"/>
                  )}
                </button>
            </div>
        </div>

        {/* Refined Search Bar */}
        <div className="relative">
            <input
                type="text"
                className="block w-full pl-6 pr-12 py-4 border-0 rounded-2xl bg-[#1b1b2f] text-gray-100 placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-yellow-400/30 transition-all duration-300 shadow-lg"
                placeholder="Search Duas..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
            />
            <div className="absolute inset-y-0 right-0 pr-4 flex items-center">
                {searchQuery ? (
                  <button onClick={() => setSearchQuery('')} className="text-gray-500 hover:text-white">
                    <XMarkIcon className="w-5 h-5" />
                  </button>
                ) : (
                  <SearchIcon className="w-5 h-5 text-gray-500" />
                )}
            </div>
        </div>

      {searchQuery ? (
          <div className="space-y-4 animate-fade-in">
             {filteredDuas.map(dua => (
                 <DuaCard key={dua.id} dua={dua} />
             ))}
             {filteredDuas.length === 0 && (
                 <div className="text-center text-gray-500 py-10">No results found</div>
             )}
          </div>
      ) : (
          <>
            {/* Daily Feature Card */}
            <div 
              onClick={() => setIsDuaModalOpen(true)}
              className="relative rounded-[2.5rem] overflow-hidden shadow-2xl h-64 w-full flex items-end group cursor-pointer"
            >
                <div className="absolute inset-0 bg-gradient-to-br from-[#1b1b2f] to-[#0c1021] z-0"></div>

                <div className="relative z-10 p-8 w-full flex flex-col justify-end">
                   <h3 className="text-2xl font-bold text-white mb-3">Dua of the Day</h3>

                   {dailyDua && (
                       <div className="bg-[#0c1021]/80 backdrop-blur-xl rounded-2xl p-4 border border-white/10">
                           <p className="text-gray-300 text-sm line-clamp-2 italic">"{dailyDua.translation_en}"</p>
                       </div>
                   )}
                </div>
            </div>

            <button
                onClick={onEnterSleepMode}
                className="w-full flex items-center justify-between bg-white/5 backdrop-blur-sm text-gray-100 px-6 py-6 rounded-[2rem] border border-white/5 group hover:bg-white/10 transition-all"
            >
                <div className="flex items-center gap-4">
                    <div className="p-3 bg-indigo-500/10 rounded-2xl text-indigo-400">
                        <MoonIcon className="w-6 h-6"/>
                    </div>
                    <span className="text-lg font-bold">Sleep Mode</span>
