      {/* Dua Modal for Daily Dua */}
      {isDuaModalOpen && dailyDua && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/95 backdrop-blur-3xl animate-fade-in" onClick={() => setIsDuaModalOpen(false)}>
